import styled from "styled-components";

export const Card = styled.div`
    display: flex;
    justify-content: center;
    padding: 15px;
    background-color: #fec453d9;
    border-radius: 10px;
    width: 30%;
    width: ${(props) => (props.origem === "form" && "35%")};
    height: 100%;
`;

export const Panel = styled.div`
    width: 90%;
    padding-top: 20%;
    position: relative;
    height:100%;
    `;

export const Picture = styled.img`
    position: absolute;
    top: 0;
    right: 0;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 75%;
    height: ${(props) => (props.origem === "form" && "60%")};
    border-radius: 50%;
`;

export const TitleProduto = styled.h3`
    font-size: 2em;
`;

export const DescProduto = styled.p`
    display: ${(props)=>(props.origem === "form" && "none")};
    font-size: 1.6em;
`;
